import json

def to_list(v):
    if v is None:
        return []
    if isinstance(v, list):
        return v
    s = str(v).strip()
    if s.startswith('[') and s.endswith(']'):
        try:
            data = json.loads(s)
            if isinstance(data, list):
                return data
        except Exception:
            pass
    return [x.strip() for x in s.split(',') if x is not None and str(x).strip() != '']

lat_in     = to_list(input_data.get('lat'))
long_in    = to_list(input_data.get('long'))
code_in    = to_list(input_data.get('tree_code'))
type_in    = to_list(input_data.get('tree_type'))
order_in   = to_list(input_data.get('order_id'))   # nieuw veld

n = max(len(lat_in), len(long_in), len(code_in), len(type_in), len(order_in))
rows = []
for i in range(n):
    row = {}
    if i < len(code_in):
        row["tree_code"] = code_in[i]
    if i < len(lat_in):
        row["lat"] = float(str(lat_in[i]).replace(',', '.')) if str(lat_in[i]).strip() != '' else None
    if i < len(long_in):
        row["long"] = float(str(long_in[i]).replace(',', '.')) if str(long_in[i]).strip() != '' else None
    if i < len(type_in):
        t = str(type_in[i]).strip()
        row["tree_type"] = t if t != '' else None
    if i < len(order_in):
        o = str(order_in[i]).strip()
        row["order_id"] = o if o != '' else None

    # verwijder lege waarden
    row = {k: v for k, v in row.items() if v not in (None, "", [])}
    if row:
        rows.append(row)

# Return JSON string (not a Python list)
return {
    "Assigned_Trees": json.dumps(rows),
    "count": len(rows)
}

