import json, ast
from datetime import datetime

raw = input_data.get("rows","[]")

# Parse rows (accept JSON or Python repr)
if isinstance(raw, list):
    rows = raw
else:
    s = str(raw).strip()
    if not s:
        rows = []
    else:
        try:
            rows = json.loads(s)
        except Exception:
            rows = ast.literal_eval(s)

def to_ddmmyyyy(s):
    s = (s or "").strip()
    if not s:
        return ""
    # Try several formats, end with first-10-chars YYYY-MM-DD
    fmts = (
        "%Y-%m-%d",
        "%d-%m-%Y",
        "%Y-%m-%d %H:%M:%S",
        "%Y-%m-%dT%H:%M:%S",
        "%Y-%m-%dT%H:%M:%S.%f",
    )
    for fmt in fmts:
        try:
            return datetime.strptime(s[:len(fmt)], fmt).strftime("%d-%m-%Y")
        except Exception:
            pass
    try:
        return datetime.strptime(s[:10], "%Y-%m-%d").strftime("%d-%m-%Y")
    except Exception:
        return ""

codes, lats, longs, types, dates_raw, dates_ddmmyyyy = [], [], [], [], [], []
creator_rows = []

for r in rows or []:
    code = (r.get("tree_code") or "").strip()
    lat  = r.get("lat")
    lon  = r.get("long")
    typ  = r.get("tree_type") or ""
    draw = (r.get("planted_date") or "").strip()
    dddm = to_ddmmyyyy(draw)

    codes.append(code)
    lats.append(lat)
    longs.append(lon)
    types.append(typ)
    dates_raw.append(draw)
    dates_ddmmyyyy.append(dddm)

    creator_rows.append({
        "tree_code": code,
        "lat": lat,
        "long": lon,
        "tree_type": typ,
        "planted_date": dddm,  # <-- dd-MM-YYYY for Creator
    })

out = {
    # arrays (use these if you see the dynamic subform panel)
    "sf_tree_code": codes,
    "sf_lat": lats,
    "sf_long": longs,
    "sf_tree_type": types,
    "sf_planted_date_ddmmyyyy": dates_ddmmyyyy,

    # original json (ISO dates) – usually NOT what Creator wants
    "trees_json": json.dumps(rows, ensure_ascii=False),

    # 👇 the one you asked for: dd-MM-YYYY dates for Creator
    "trees_json_creator": json.dumps(creator_rows, ensure_ascii=False),
}

if codes:
    out.update({
        "first_tree_code": codes[0],
        "first_tree_lat": lats[0],
        "first_tree_long": longs[0],
        "first_tree_type": types[0],
        "first_planted_date_ddmmyyyy": dates_ddmmyyyy[0],
    })

return out

