import json
from itertools import zip_longest
from datetime import datetime

def to_list(v):
    if v is None:
        return []
    if isinstance(v, list):
        return v
    s = str(v).strip()
    if s.startswith('[') and s.endswith(']'):
        try:
            d = json.loads(s)
            if isinstance(d, list):
                return d
        except Exception:
            pass
    return [x.strip() for x in s.split(',') if str(x).strip()]

def parse_dt(s):
    if not s:
        return None
    for fmt in ("%Y-%m-%dT%H:%M:%S.%fZ",
                "%Y-%m-%dT%H:%M:%SZ",
                "%Y-%m-%dT%H:%M:%S.%f",
                "%Y-%m-%dT%H:%M:%S"):
        try:
            return datetime.strptime(str(s), fmt)
        except Exception:
            pass
    return None

ids      = to_list(input_data.get('ids'))
codes    = to_list(input_data.get('tree_codes'))
types    = to_list(input_data.get('tree_types'))
lats     = to_list(input_data.get('lats'))
longs    = to_list(input_data.get('longs'))
claimed  = to_list(input_data.get('claimed_at')) or to_list(input_data.get('claimed_at_utc'))
user_ids = to_list(input_data.get('user_ids'))

rows = []
for i, code, typ, la, lo, cl, uid in zip_longest(ids, codes, types, lats, longs, claimed, user_ids, fillvalue=''):
    rows.append({
        "id": i,
        "tree_code": code,
        "tree_type": typ,
        "lat": la,
        "long": lo,
        "claimed_at_utc": cl,
        "user_id": uid,
        "_dt": parse_dt(cl)  # alleen voor sortering
    })

# sorteer op datum, onbekenden onderaan
rows.sort(key=lambda r: (r["_dt"] is None, r["_dt"]))

# verwijder niet-serialiseerbaar veld en normaliseer waarden
clean_rows = []
for r in rows:
    r = dict(r)
    r.pop("_dt", None)                 # dit voorkomt de Zapier-fout
    for k, v in list(r.items()):
        if isinstance(v, datetime):
            r[k] = v.isoformat() + "Z"
        elif v is None:
            r[k] = ""
        else:
            r[k] = str(v)
    clean_rows.append(r)

return {"count": len(clean_rows), "rows": clean_rows}
return {"count": len(clean_rows), "rows_json": json.dumps(clean_rows)}

import json
from itertools import zip_longest

def as_rows(v):
    if isinstance(v, list):
        return v
    if isinstance(v, str):
        try:
            d = json.loads(v)
            if isinstance(d, list):
                return d
        except Exception:
            pass
    return []

def to_list(v):
    if v is None:
        return []
    if isinstance(v, list):
        return v
    s = str(v).strip()
    if s.startswith('[') and s.endswith(']'):
        try:
            d = json.loads(s)
            if isinstance(d, list):
                return d
        except Exception:
            pass
    return [x.strip() for x in s.split(',') if x.strip()]

def cell(x):
    return ("" if x is None else str(x)).replace("\t", " ").replace("\n", " ").strip()

# 1) probeer rows direct (als stap 3 een array/JSON levert)
rows = as_rows(input_data.get("rows"))

# 2) zo niet: reconstrueer uit line-items (als stap 3 alleen “Rows …” velden heeft)
if not rows:
    ids      = to_list(input_data.get('ids'))
    codes    = to_list(input_data.get('tree_codes'))
    types    = to_list(input_data.get('tree_types'))
    lats     = to_list(input_data.get('lats'))
    longs    = to_list(input_data.get('longs'))
    claimed  = to_list(input_data.get('claimed_at')) or to_list(input_data.get('claimed_at_utc'))
    user_ids = to_list(input_data.get('user_ids'))
    rows = []
    for i, code, typ, la, lo, cl, uid in zip_longest(ids, codes, types, lats, longs, claimed, user_ids, fillvalue=''):
        rows.append({
            "tree_code": code, "tree_type": typ,
            "lat": la, "long": lo,
            "claimed_at_utc": cl, "user_id": uid
        })

# 3) bouw body
lines = [
    f"{cell(r.get('tree_code'))}\t{cell(r.get('tree_type'))}\t"
    f"{cell(r.get('lat'))},{cell(r.get('long'))}\t"
    f"{cell(r.get('claimed_at_utc') or r.get('claimed_at'))}\t"
    f"{cell(r.get('user_id'))}"
    for r in rows
]

header = "TreeCode\tType\tLat,Long\tClaimedAt(UTC)\tUserId"
body = "Monthly claimed trees\n\n" + header + ("\n" + "\n".join(lines) if lines else "\n(no claims found for the period)")

return {"count": len(rows), "body": body}

import json

def to_list(v):
    """Normalize Zapier inputs into a list."""
    if v is None:
        return []
    if isinstance(v, list):
        return [x for x in v if x not in (None, "")]
    s = str(v).strip()
    if not s:
        return []
    # If Zapier passed a JSON-ish list as a string, try to parse
    if (s.startswith("[") and s.endswith("]")):
        try:
            parsed = json.loads(s)
            if isinstance(parsed, list):
                return [x for x in parsed if x not in (None, "")]
        except Exception:
            pass
    # Comma-separated string
    if "," in s:
        return [x.strip() for x in s.split(",") if x.strip()]
    return [s]

def to_int(v):
    if v in (None, ""):
        return None
    try:
        return int(str(v).strip())
    except Exception:
        return None

def to_float(v):
    if v in (None, ""):
        return None
    try:
        return float(str(v).strip())
    except Exception:
        return None

# Read Zapier inputs
codes    = to_list(input_data.get("tree_codes"))
types    = to_list(input_data.get("tree_types"))
lats     = to_list(input_data.get("lats"))
longs    = to_list(input_data.get("longs"))
emails   = to_list(input_data.get("emails"))
user_ids = to_list(input_data.get("user_ids"))

# Build rows (include user_id)
n = max(len(codes), len(types), len(lats), len(longs), len(emails), len(user_ids))
rows = []

for i in range(n):
    row = {
        "tree_code": codes[i] if i < len(codes) else None,
        "tree_type": types[i] if i < len(types) else None,
        "lat": to_float(lats[i]) if i < len(lats) else None,
        "long": to_float(longs[i]) if i < len(longs) else None,
        "Email_ontvanger": emails[i] if i < len(emails) else None,
        "user_id": to_int(user_ids[i]) if i < len(user_ids) else None,
    }
    rows.append(row)

return {
    "Assigned_Trees": json.dumps(rows),
    "count": len(rows)
}

